1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = { type: string };
12	type QuoteStep = { op: "quote"; items: Item[] };
13	type Step = QuoteStep;
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	
16	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
17	
18	const FIRST_INSURANCE_RATE = 0.1;
19	
20	const quotePremium = (items: Item[]): number => {
21	  const base = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
22	  const firstInsurance = base * FIRST_INSURANCE_RATE;
23	  return Math.ceil(base + firstInsurance + PROCESSING_FEE);
24	};
25	
26	export const processScenario = (scenario: Scenario): unknown => {
27	  const results = scenario.steps.map((step) => ({
28	    premium: quotePremium(step.items),
29	  }));
30	  return { results };
31	};
